module RefModule(clk, rst, load, d, q);

    input  clk;
    input  rst;
    input  load;
    input  [3:0] d;
    output reg [3:0] q;

      wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge rst or posedge dbg_halt) begin
        if (rst)
            q <= 4'b0000;
        else if (load)
            q <= d;
    end

endmodule
